#include <bits/stdc++.h>
using namespace std;
int n,m,a[100005];
long double sum=0;
double num=0;
int main()
{
	cin>>n>>m;
    for(int i=1;i<=n;i++) cin>>a[i];
    sort(a+1,a+1+n);
    for(int i=1;i<=n;i++)
    {
        if(num<=a[i]) sum+=m;
        num=sum/i;
    }
    printf("%.2lf ",num);
    num=0;
    sum=0;
    for(int i=n;i>0;i--)
    {
        if(num<=a[i]) sum+=m;
        num=sum/(n-i+1);
    }
    printf("%.2lf",num);
	return 0;
}
